let data = $json.body;
let error;

if (!data.ingredients || data.ingredients.length < 2) {
  return { json: { error: "NOT_ENOUGH_INGREDIENTS" } };
}

for (let ing of data.ingredients) {
  if (!ing.quantity || ing.quantity <= 0) {
    return { json: { error: "INVALID_QUANTITY" } };
  }

  if (!["gram", "ml", "piece"].includes(ing.unit)) {
    return { json: { error: "INVALID_UNIT" } };
  }
}

if (error) {
  return { json: { error: "..." } };
}



return {
  json: {
    ingredients: data.ingredients,
    portions: data.portions,
    chefs: data.chefs,
    time: data.time,
    cuisine: data.cuisine,
    diet: data.diet,
  }
};

